#[test]
fn api_response_ok_creates_success_response() {
    let response = ApiResponse::ok("workers list", vec!["w1", "w2"]);
    assert!(response.success);
    assert_eq!(response.command, Some("workers list".to_string()));
    assert_eq!(response.api_version, "1.0");
    assert!(response.data.is_some());
    assert!(response.error.is_none());
    assert!(response.timestamp > 0);
}

#[test]
fn api_response_err_creates_failure_response() {
    let error = ApiError::from_code(ErrorCode::ConfigNotFound);
    let response: ApiResponse<()> = ApiResponse::err("config show", error);

    assert!(!response.success);
    assert!(response.data.is_none());
    assert!(response.error.is_some());
    assert_eq!(response.error.as_ref().unwrap().code, "RCH-E001");
}

#[test]
fn api_response_serialization_omits_empty_fields() {
    let response = ApiResponse::ok("test", "data");
    let json = serde_json::to_string(&response).unwrap();

    // Should not contain null fields
    assert!(!json.contains("\"request_id\":null"));
    assert!(!json.contains("\"error\":null"));
}

#[test]
fn api_response_with_request_id() {
    let response = ApiResponse::ok("test", "data")
        .with_request_id("req-12345");

    assert_eq!(response.request_id, Some("req-12345".to_string()));
}

#[test]
fn api_response_from_result_ok() {
    let result: Result<String, ApiError> = Ok("success".to_string());
    let response: ApiResponse<String> = result.into();

    assert!(response.success);
    assert_eq!(response.data, Some("success".to_string()));
}

#[test]
fn api_response_from_result_err() {
    let result: Result<(), ApiError> = 
        Err(ApiError::from_code(ErrorCode::SshConnectionFailed));
    let response: ApiResponse<()> = result.into();

    assert!(!response.success);
    assert!(response.error.is_some());
}

#[test]
fn api_response_builder_pattern() {
    let response: ApiResponse<String> = ApiResponseBuilder::new()
        .command("workers list")
        .request_id("req-456")
        .data("test data".to_string())
        .build();

    assert!(response.success);
    assert_eq!(response.command, Some("workers list".to_string()));
    assert_eq!(response.request_id, Some("req-456".to_string()));
}

#[test]
fn api_response_timestamp_is_reasonable() {
    let response = ApiResponse::ok("test", ());
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs();

    // Timestamp should be within 5 seconds of now
    assert!((response.timestamp as i64 - now as i64).abs() < 5);
}
